import sys
import os
import json
import re

def validate(data, schema, path='$'):
    """Recursively validate data against a JSON schema subset. Returns list of error strings."""
    errors = []

    if schema is None or schema == {}:
        return errors

    # Handle $ref (not implemented - skip)
    # Handle allOf, anyOf, oneOf
    if 'allOf' in schema:
        for sub in schema['allOf']:
            errors.extend(validate(data, sub, path))
        return errors

    if 'anyOf' in schema:
        sub_errors = []
        for sub in schema['anyOf']:
            errs = validate(data, sub, path)
            if not errs:
                return []
            sub_errors.extend(errs)
        errors.append(f'{path}: does not match any of the anyOf schemas')
        return errors

    if 'oneOf' in schema:
        match_count = 0
        for sub in schema['oneOf']:
            errs = validate(data, sub, path)
            if not errs:
                match_count += 1
        if match_count != 1:
            errors.append(f'{path}: must match exactly one of the oneOf schemas (matched {match_count})')
        return errors

    # Type checking
    expected_type = schema.get('type')
    if expected_type:
        type_map = {
            'string': str,
            'number': (int, float),
            'integer': int,
            'boolean': bool,
            'array': list,
            'object': dict,
            'null': type(None)
        }
        if isinstance(expected_type, list):
            # Union type
            valid_types = tuple(t for et in expected_type for t in (type_map.get(et, ()) if isinstance(type_map.get(et), tuple) else (type_map.get(et, ()),)))
            if not isinstance(data, valid_types):
                errors.append(f'{path}: expected one of types {expected_type}, got {type(data).__name__}')
                return errors
        else:
            expected_py = type_map.get(expected_type)
            if expected_py:
                # Special case: bool is subclass of int in Python
                if expected_type == 'integer' and isinstance(data, bool):
                    errors.append(f'{path}: expected integer, got boolean')
                    return errors
                if expected_type == 'number' and isinstance(data, bool):
                    errors.append(f'{path}: expected number, got boolean')
                    return errors
                if not isinstance(data, expected_py):
                    errors.append(f'{path}: expected type {expected_type}, got {type(data).__name__}')
                    return errors

    # Enum validation
    if 'enum' in schema:
        if data not in schema['enum']:
            errors.append(f'{path}: value {json.dumps(data)} not in enum {json.dumps(schema["enum"])}')

    # Const validation
    if 'const' in schema:
        if data != schema['const']:
            errors.append(f'{path}: value must be {json.dumps(schema["const"])}')

    # String constraints
    if isinstance(data, str):
        if 'minLength' in schema and len(data) < schema['minLength']:
            errors.append(f'{path}: string length {len(data)} < minLength {schema["minLength"]}')
        if 'maxLength' in schema and len(data) > schema['maxLength']:
            errors.append(f'{path}: string length {len(data)} > maxLength {schema["maxLength"]}')
        if 'pattern' in schema:
            if not re.search(schema['pattern'], data):
                errors.append(f'{path}: string does not match pattern {schema["pattern"]}')

    # Numeric constraints
    if isinstance(data, (int, float)) and not isinstance(data, bool):
        if 'minimum' in schema and data < schema['minimum']:
            errors.append(f'{path}: {data} < minimum {schema["minimum"]}')
        if 'maximum' in schema and data > schema['maximum']:
            errors.append(f'{path}: {data} > maximum {schema["maximum"]}')
        if 'exclusiveMinimum' in schema and data <= schema['exclusiveMinimum']:
            errors.append(f'{path}: {data} <= exclusiveMinimum {schema["exclusiveMinimum"]}')
        if 'exclusiveMaximum' in schema and data >= schema['exclusiveMaximum']:
            errors.append(f'{path}: {data} >= exclusiveMaximum {schema["exclusiveMaximum"]}')
        if 'multipleOf' in schema and schema['multipleOf'] != 0:
            if data % schema['multipleOf'] != 0:
                errors.append(f'{path}: {data} is not a multiple of {schema["multipleOf"]}')

    # Array constraints
    if isinstance(data, list):
        if 'minItems' in schema and len(data) < schema['minItems']:
            errors.append(f'{path}: array length {len(data)} < minItems {schema["minItems"]}')
        if 'maxItems' in schema and len(data) > schema['maxItems']:
            errors.append(f'{path}: array length {len(data)} > maxItems {schema["maxItems"]}')
        if 'uniqueItems' in schema and schema['uniqueItems']:
            seen = []
            for item in data:
                s = json.dumps(item, sort_keys=True)
                if s in seen:
                    errors.append(f'{path}: array contains duplicate items')
                    break
                seen.append(s)
        items_schema = schema.get('items')
        if items_schema:
            for i, item in enumerate(data):
                errors.extend(validate(item, items_schema, f'{path}[{i}]'))

    # Object constraints
    if isinstance(data, dict):
        required = schema.get('required', [])
        for field in required:
            if field not in data:
                errors.append(f'{path}: missing required field "{field}"')
        properties = schema.get('properties', {})
        for prop, prop_schema in properties.items():
            if prop in data:
                errors.extend(validate(data[prop], prop_schema, f'{path}.{prop}'))
        additional = schema.get('additionalProperties')
        if additional is False:
            extra = set(data.keys()) - set(properties.keys())
            for key in extra:
                errors.append(f'{path}: unexpected additional property "{key}"')
        elif isinstance(additional, dict):
            extra = set(data.keys()) - set(properties.keys())
            for key in extra:
                errors.extend(validate(data[key], additional, f'{path}.{key}'))
        if 'minProperties' in schema and len(data) < schema['minProperties']:
            errors.append(f'{path}: object has {len(data)} properties < minProperties {schema["minProperties"]}')
        if 'maxProperties' in schema and len(data) > schema['maxProperties']:
            errors.append(f'{path}: object has {len(data)} properties > maxProperties {schema["maxProperties"]}')

    return errors

def main():
    inputs = json.loads(os.environ.get('SKILL_INPUTS', '{}'))
    data = inputs.get('data')
    schema = inputs.get('schema', {})

    # If data is a file path string, load it
    if isinstance(data, str) and os.path.exists(data):
        try:
            with open(data, 'r', encoding='utf-8') as f:
                data = json.load(f)
        except Exception as e:
            print(json.dumps({'valid': False, 'errors': [f'Failed to load data file: {e}']}))
            return

    if data is None:
        print(json.dumps({'valid': False, 'errors': ['No data provided']}))
        return

    errors = validate(data, schema)
    print(json.dumps({'valid': len(errors) == 0, 'errors': errors}))

if __name__ == '__main__':
    main()
